1	export function nextGeneration(
2	  liveCells: [number, number][],
3	): [number, number][] {
4	  const liveSet = new Set(liveCells.map(([x, y]) => `${x},${y}`));
5	
6	  const survivors: [number, number][] = [];
7	
8	  for (const [x, y] of liveCells) {
9	    let neighborCount = 0;
10	    for (let dx = -1; dx <= 1; dx++) {
11	      for (let dy = -1; dy <= 1; dy++) {
12	        if (dx === 0 && dy === 0) continue;
13	        if (liveSet.has(`${x + dx},${y + dy}`)) neighborCount++;
14	      }
15	    }
16	    if (neighborCount === 2 || neighborCount === 3) {
17	      survivors.push([x, y]);
18	    }
19	  }
20	
21	  return survivors;
